#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        long long q = N / K;
        long long r = N % K;
        long long D = (r==0) ? q : q+1;
        long long X = (r==0) ? K : r;
        printf("%lld %lld", D, X);
        if(T) printf("\n");
    }
    return 0;
}

